// Professional RSS Sources — curated for trading/macro/tech signals
const sources = [
  // === Macro / Economics ===
  { url: 'https://feeds.content.dowjones.io/public/rss/mw_topstories', category: 'macro', priority: 1 },
  { url: 'https://www.economist.com/finance-and-economics/rss.xml', category: 'macro', priority: 1 },
  { url: 'https://www.ft.com/rss/home/uk', category: 'macro', priority: 2 },
  { url: 'https://www.bloomberg.com/feeds/podcasts/etf_report.xml', category: 'macro', priority: 2 },

  // === Commodities / Energy ===
  { url: 'https://www.reuters.com/arc/outboundfeeds/v3/all/?outputType=xml&section=commodities', category: 'commodities', priority: 1 },
  { url: 'https://oilprice.com/rss/main', category: 'commodities', priority: 1 },
  { url: 'https://www.eia.gov/rss/todayinenergy.xml', category: 'commodities', priority: 2 },
  { url: 'https://www.kitco.com/rss/', category: 'commodities', priority: 2 },

  // === Tech / AI ===
  { url: 'https://techcrunch.com/feed/', category: 'tech', priority: 1 },
  { url: 'https://arstechnica.com/feed/', category: 'tech', priority: 2 },
  { url: 'https://www.theverge.com/rss/index.xml', category: 'tech', priority: 2 },
  { url: 'https://venturebeat.com/feed/', category: 'tech', priority: 2 },
  { url: 'https://hnrss.org/frontpage?points=100', category: 'tech', priority: 1 },

  // === Cybersecurity ===
  { url: 'https://krebsonsecurity.com/feed/', category: 'cyber', priority: 1 },
  { url: 'https://feeds.feedburner.com/TheHackersNews', category: 'cyber', priority: 1 },
  { url: 'https://www.bleepingcomputer.com/feed/', category: 'cyber', priority: 2 },
  { url: 'https://www.schneier.com/feed/atom/', category: 'cyber', priority: 2 },

  // === Trading / Finance ===
  { url: 'https://www.forexlive.com/feed/', category: 'trading', priority: 1 },
  { url: 'https://www.dailyfx.com/feeds/all', category: 'trading', priority: 2 },
  { url: 'https://www.investing.com/rss/news_25.rss', category: 'trading', priority: 3 },
  { url: 'https://www.zerohedge.com/fullrss2.xml', category: 'trading', priority: 2 },

  // === Science / Research ===
  { url: 'https://arxiv.org/rss/cs.AI', category: 'research', priority: 2 },
  { url: 'https://arxiv.org/rss/q-fin.TR', category: 'research', priority: 2 },
  { url: 'https://www.nature.com/nature.rss', category: 'research', priority: 3 },

  // === Geopolitics ===
  { url: 'https://www.cfr.org/feeds/regions/middle-east-and-north-africa', category: 'geopolitics', priority: 1 },
  { url: 'https://www.aljazeera.com/xml/rss/all.xml', category: 'geopolitics', priority: 2 },

  // === Israel / Local ===
  { url: 'https://www.globes.co.il/webservice/rss/rssfeeds.asmx/feeds/GetRssFeeds?iid=100', category: 'local', priority: 1 },
  { url: 'https://www.calcalist.co.il/GeneralRSS/0,17149,L-8,00.xml', category: 'local', priority: 1 },
  { url: 'https://www.themarker.com/cmlink/1.135', category: 'local', priority: 2 },
];

// Filter: only high-priority sources during heavy news days
const today = new Date();
const isWeekend = today.getDay() === 0 || today.getDay() === 6;
const priorityThreshold = isWeekend ? 2 : 3;

const filteredSources = sources
  .filter(s => s.priority <= priorityThreshold)
  .sort((a, b) => a.priority - b.priority);

return filteredSources.map(s => ({ json: s }));

// Filter out alarmist/panic headlines before they enter the pipeline
const item = $input.first().json;
const title = (item.title || '').toLowerCase();
const content = (item.content || item.description || '').toLowerCase();
const fullText = title + ' ' + content;

// Alarmist keyword patterns to filter OUT
const alarmPatterns = [
  'crash', 'panic', 'collapse', 'apocalypse', 'doomsday',
  'bloodbath', 'plunge', 'plummet', 'freefall', 'meltdown',
  'armageddon', 'catastrophe', 'devastating', 'wipe out',
  'worst day', 'worst week', 'record plunge', 'market rout',
  'death cross', 'black swan', 'perfect storm',
];

const isAlarmist = alarmPatterns.some(p => fullText.includes(p));

// Sentiment scoring (simple heuristic)
const positiveWords = ['surge', 'rally', 'breakthrough', 'record high', 'bullish', 'growth', 'innovation', 'opportunity'];
const negativeWords = ['decline', 'drop', 'fall', 'bearish', 'risk', 'warning', 'concern', 'threat'];

let posCount = positiveWords.filter(w => fullText.includes(w)).length;
let negCount = negativeWords.filter(w => fullText.includes(w)).length;

// Skip alarmist items entirely
if (isAlarmist) {
  return null;
}

return {
  ...item,
  sentiment: posCount > negCount ? 'positive' : negCount > posCount ? 'negative' : 'neutral',
  sentiment_score: posCount - negCount,
  is_alarmist: false,
  filtered_at: new Date().toISOString(),
};

// Simple dedup: track seen titles, skip near-duplicates
const seenTitles = $vars.seenTitles || new Set();

// Convert to array if needed (n8n stores as plain object)
if (seenTitles.constructor !== Set) {
  $vars.seenTitles = new Set(Object.keys(seenTitles));
}

const title = ($input.first().json.title || '').substring(0, 100).toLowerCase().trim();

if ($vars.seenTitles.has(title)) {
  return null;
}

$vars.seenTitles.add(title);
// Keep only last 200 titles to avoid memory bloat
if ($vars.seenTitles.size > 200) {
  const arr = [...$vars.seenTitles];
  $vars.seenTitles = new Set(arr.slice(-100));
}

return $input.first().json;

