const item = $input.first().json;
const prevNode = $('DeepSeek Enrichment').first().json;

// Extract DeepSeek response
let deepseekSummary = '';
try {
  const body = typeof prevNode === 'string' ? JSON.parse(prevNode) : prevNode;
  deepseekSummary = body.choices?.[0]?.message?.content || 'סיכום לא זמין';
} catch(e) {
  deepseekSummary = 'סיכום לא זמין';
}

// Get category emoji
const categoryEmojis = {
  macro: '🏛️',
  commodities: '🛢️',
  tech: '🤖',
  cyber: '🔒',
  trading: '📊',
  research: '🔬',
  geopolitics: '🌍',
  local: '🇮🇱'
};

const category = item.category || 'general';
const emoji = categoryEmojis[category] || '📌';

// Format as RTL Hebrew post (suitable for Telegram, LinkedIn, Twitter)
const post = `${emoji} *${item.title}*

${deepseekSummary}

🔗 ${item.link || ''}
📂 ${category} | 📅 ${new Date().toLocaleDateString('he-IL')}`;

return {
  hebrew_post: post,
  english_title: item.title,
  link: item.link,
  category: category,
  sentiment: item.sentiment,
  timestamp: new Date().toISOString(),
};

// Log errors to a simple array (store to file or alert if > threshold)
const error = $input.first().json;

$vars.errorLog = $vars.errorLog || [];
$vars.errorLog.push({
  time: new Date().toISOString(),
  error: error.message || JSON.stringify(error),
  node: error.node || 'unknown',
});

// Keep only last 50 errors
if ($vars.errorLog.length > 50) {
  $vars.errorLog = $vars.errorLog.slice(-50);
}

// Alert if error rate > 10%
const recentErrors = $vars.errorLog.filter(e => {
  const age = Date.now() - new Date(e.time).getTime();
  return age < 3600000; // last hour
});

if (recentErrors.length > 10) {
  console.error('⚠️ RSS Triage: High error rate —', recentErrors.length, 'errors in last hour');
}

return { logged: true, total_errors: $vars.errorLog.length };
